const body = $input.first().json.body || $input.first().json || {};
const message = body.message || '';
const fileContent = body.file_content || '';
const childId = body.child_id || 0;
const authToken = body.auth_token || '';

const userText = fileContent.length > 0
  ? `Extract ALL tasks, homework and exams from this document. Return ONLY a JSON array. Each item: {"title": string, "type": "homework" or "test" or "activity" or "other", "due_days": number (0=today,1=tomorrow,7=next week)}\n\nDocument:\n${fileContent.substring(0, 8000)}`
  : `Extract tasks from this Hebrew message. Return ONLY a JSON array. Each item: {"title": string, "type": "homework" or "test" or "activity" or "other", "due_days": number}\n\nMessage: ${message}`;

return [{ json: { userText, childId, authToken, message, fileContent } }];

const response = $input.first().json;
const raw = response.content?.[0]?.text || '';

let tasks = [];
try {
  const match = raw.match(/\[.*\]/s);
  if (match) tasks = JSON.parse(match[0]);
} catch(e) {}

if (!tasks.length) {
  tasks = [{ title: $node['Prepare Prompt'].json.message || 'משימה חדשה', type: 'homework', due_days: 0 }];
}

const now = Math.floor(Date.now() / 1000);
const DAY = 86400;
const childId = $node['Prepare Prompt'].json.childId;
const authToken = $node['Prepare Prompt'].json.authToken;

return tasks.slice(0, 10).map(t => ({
  json: {
    title: String(t.title || 'משימה חדשה').substring(0, 200),
    type: ['homework','test','activity','other'].includes(t.type) ? t.type : 'homework',
    status: 'pending',
    due_date: now + (Math.max(0, parseInt(t.due_days) || 0) * DAY),
    child_id: childId,
    auth_token: authToken
  }
}));
